VALUES
  ('judicial-d3df8a4a-moex-00111', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '依中央法規標準法規定，關於行政命令，下列敘述何者正確？', '["關於國家各機關組織規範得由行政命令訂之", "行政命令之原發布機關已裁併者，其廢止則由承受其業務之機關或其上級機關為之", "行政命令定有施行期限而主管機關認為需要延長者，須於期限屆滿日前發布延長即可", "各機關依其法定職權所制定之行政命令得自行發布，無須送交立法院"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
  ('judicial-d3df8a4a-moex-00112', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '司法院釋字第792號解釋：毒品危害防制條例第4條「第1項至第4項將販賣毒品與製造、運輸毒品之構成要 件併列，並對該三種犯罪態樣，科以相同之法定刑。由此推論，本條所指之『販賣』毒品行為嚴重程度，應與製 造及運輸毒品相當。所謂製造毒品係將毒品從無至有，予以生產，進而得危害他人；而運輸毒品係從一地運至他 地，使毒品流通於他地，產生危害。基於同一法理，販賣毒品罪，應在處罰『賣出』毒品，因而產生毒品危害之 行為，蓋販賣須如此解釋，其嚴重程度始與上述製造與運輸毒品之危害相當。」是屬於下列何種解釋方法？', '["文義解釋", "歷史解釋", "體系解釋", "目的解釋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
  ('judicial-d3df8a4a-moex-00113', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '有關授權明確性原則之敘述，下列何者錯誤？', '["立法機關授權行政機關發布命令，為憲法所許，只要其授權目的、內容或範圍其中之一具體明確即可", "在此原則之下，授權條款之明確程度，應與所授權訂定之法規命令對人民權利之影響相稱", "由授權之母法整體觀察，已足使人民預見行為有受處罰之可能，即與得預見行為可罰之意旨無違，不以 確信其行為之可罰為必要", "此乃法律保留原則之補充與具體化"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
  ('judicial-d3df8a4a-moex-00114', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '依據司法院大法官解釋，下列何者無須由法律明文規定？', '["消滅時效", "課徵租稅之構成要件", "公務員懲戒撤職處分之構成要件", "公務人員專案考績一次記二大過免職之構成要件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
  ('judicial-d3df8a4a-moex-00115', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '關於平等權，下列敘述何者錯誤？', '["平等權旨在防止國家恣意之差別待遇", "平等權之侵害，限於國家之作為，不作為不屬之", "基於平等權保障之要求，國家得為差別待遇", "差別待遇之目的是否合憲，係國家行為有無違反平等保障考量因素之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
  ('judicial-d3df8a4a-moex-00116', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '甲為某視聽著作之著作人，於創作完成後第5年始將該視聽著作對外公開發表，有關著作財產權的存續期 間，下列敘述何者正確？', '["若甲為法人，其著作財產權存續至創作完成時起50年", "若甲為法人，其著作財產權存續至該法人成立時起50年", "若甲為自然人，其著作財產權存續於甲的生存期間及其死亡後50年", "若甲為自然人，其著作財產權存續至該著作公開發表後50年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
  ('judicial-d3df8a4a-moex-00117', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '保險醫事服務機構當年領取之保險醫療費用超過一定數額者，應於期限內向保險人提報經會計師簽證或審 計機關審定之全民健康保險業務有關之財務報告，下列何者非財務報告應包括之報表？', '["資產負債表", "現金流量表", "損益表", "淨值變動表"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
  ('judicial-d3df8a4a-moex-00118', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '當事人得以要約與承諾之方式成立契約。關於要約，下列敘述何者錯誤？', '["貨物標定賣價陳列者，依民法規定推定為要約", "契約之要約人，因要約而受拘束", "對話為要約者，除要約人另有意思表示外，非立時承諾，即失其拘束力", "要約定有承諾期限者，非於其期限內為承諾，失其拘束力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
  ('judicial-d3df8a4a-moex-00119', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '依民法之規定，總會決議之內容違反法令或章程，其效力為何？', '["無效", "無效，但不得以其無效對抗善意之第三人", "須經主管機關、檢察官或利害關係人向法院聲請，以宣告其行為為無效", "社員得於決議後3個月內請求法院撤銷其決議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL),
  ('judicial-d3df8a4a-moex-00120', 'judicial-d3df8a4a', 'judicial-d3df8a4a-moex-111-3d2b73b6', 'sub-judicial-d3df8a4a-08', NULL, 'single_choice', '甲將自己的A車以60萬元賣給乙，雙方約定下個月初交車及付款。不料，於交車前數日，A車於公共停 車場中遭雷電擊中而燒毀。依民法規定，下列敘述何者錯誤？', '["甲對乙免給付義務", "乙對甲免支付價金", "甲應對乙負債務不履行的損害賠償責任", "乙不得向甲請求給付A車"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:54+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "109", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-財經實務組"}'::jsonb, NULL)
